import type { LayoutLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

const WORKERS_QUERY = gql`
	query WorkersByProject($projectID: String!) {
		workersByProject(projectID: $projectID, first: 50) {
			edges {
				node {
					id
					kind
					state
					status
					harness
					model
					currentBead
					attempts
					successes
					failures
					startedAt
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`

interface WorkerNode {
	id: string
	kind: string
	state: string
	status: string | null
	harness: string | null
	model: string | null
	currentBead: string | null
	attempts: number | null
	successes: number | null
	failures: number | null
	startedAt: string | null
}

interface WorkerEdge {
	node: WorkerNode
	cursor: string
}

interface WorkerConnection {
	edges: WorkerEdge[]
	pageInfo: { hasNextPage: boolean; endCursor: string | null }
	totalCount: number
}

interface WorkersResult {
	workersByProject: WorkerConnection
}

export const load: LayoutLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	const data = await client.request<WorkersResult>(WORKERS_QUERY, {
		projectID: params.projectId
	})
	return {
		projectId: params.projectId,
		workers: data.workersByProject
	}
}
import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';

const WORKER_QUERY = gql`
	query WorkerDetail($id: ID!) {
		worker(id: $id) {
			id
			kind
			state
			status
			harness
			model
			effort
			once
			pollInterval
			startedAt
			finishedAt
			currentBead
			lastError
			attempts
			successes
			failures
			currentAttempt {
				attemptId
				beadId
				phase
				startedAt
				elapsedMs
			}
			recentEvents {
				kind
				text
				name
				inputs
				output
			}
		}
	}
`;

const WORKER_LOG_QUERY = gql`
	query WorkerLog($workerID: ID!) {
		workerLog(workerID: $workerID) {
			stdout
			stderr
		}
	}
`;

interface CurrentAttempt {
	attemptId: string;
	beadId: string | null;
	phase: string;
	startedAt: string;
	elapsedMs: number;
}

export interface WorkerDetail {
	id: string;
	kind: string;
	state: string;
	status: string | null;
	harness: string | null;
	model: string | null;
	effort: string | null;
	once: boolean | null;
	pollInterval: string | null;
	startedAt: string | null;
	finishedAt: string | null;
	currentBead: string | null;
	lastError: string | null;
	attempts: number | null;
	successes: number | null;
	failures: number | null;
	currentAttempt: CurrentAttempt | null;
	recentEvents: WorkerRecentEvent[];
}

export interface WorkerRecentEvent {
	kind: string;
	text: string | null;
	name: string | null;
	inputs: string | null;
	output: string | null;
}

interface WorkerResult {
	worker: WorkerDetail | null;
}

interface WorkerLogResult {
	workerLog: { stdout: string; stderr: string };
}

export const load: PageLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const [workerResult, logResult] = await Promise.all([
		client.request<WorkerResult>(WORKER_QUERY, { id: params.workerId }),
		client
			.request<WorkerLogResult>(WORKER_LOG_QUERY, { workerID: params.workerId })
			.catch(() => ({ workerLog: { stdout: '', stderr: '' } }))
	]);
	return {
		worker: workerResult.worker
			? { ...workerResult.worker, recentEvents: workerResult.worker.recentEvents ?? [] }
			: null,
		initialLog: logResult.workerLog.stdout
	};
};

import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

const SESSIONS_QUERY = gql`
	query AgentSessions($first: Int) {
		agentSessions(first: $first) {
			edges {
				node {
					id
					projectId
					beadId
					harness
					model
					effort
					status
					startedAt
					endedAt
					durationMs
					cost
					tokens {
						prompt
						completion
						total
						cached
					}
					outcome
					detail
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`

export const SESSION_DETAIL_QUERY = gql`
	query AgentSessionDetail($id: ID!) {
		agentSession(id: $id) {
			id
			prompt
			response
			stderr
		}
	}
`

interface TokenUsage {
	prompt: number | null
	completion: number | null
	total: number | null
	cached: number | null
}

export interface SessionNode {
	id: string
	projectId: string
	beadId: string | null
	harness: string
	model: string
	effort: string
	status: string
	startedAt: string
	endedAt: string | null
	durationMs: number
	cost: number | null
	tokens: TokenUsage | null
	outcome: string | null
	detail: string | null
	prompt?: string | null
	response?: string | null
	stderr?: string | null
}

interface SessionEdge {
	node: SessionNode
	cursor: string
}

interface SessionConnection {
	edges: SessionEdge[]
	pageInfo: { hasNextPage: boolean; endCursor: string | null }
	totalCount: number
}

interface SessionsResult {
	agentSessions: SessionConnection
}

export const load: PageLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	const data = await client.request<SessionsResult>(SESSIONS_QUERY, { first: 100 })
	const filteredEdges = data.agentSessions.edges.filter(
		(e) => e.node.projectId === params.projectId
	)
	return {
		projectId: params.projectId,
		sessions: {
			...data.agentSessions,
			edges: filteredEdges,
			totalCount: filteredEdges.length
		}
	}
}

